/**
 * MedX schema forms runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * JSON schema for PO, batch, and lot forms.
 */
const SCHEMA_TOKENS = Object.freeze({
  primary: { value: "forms-schema-primary", scope: "forms" },
  secondary: { value: "forms-schema-secondary", scope: "forms" },
  muted: { value: "forms-schema-muted", scope: "forms" },
  accent: { value: "forms-schema-accent", scope: "forms" },
  surface: { value: "forms-schema-surface", scope: "forms" },
});

const SCHEMA_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const SCHEMA_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const schemaRegistry = new Map();
const SCHEMA_listeners = new Set();
let SCHEMA_seq = 0;

function createSchemaId(prefix = "medx-forms-schema") {
  SCHEMA_seq += 1;
  return `${prefix}-${SCHEMA_seq}`;
}

function registerSchema(config = {}) {
  const entryId = config.id ?? createSchemaId();
  const preset = SCHEMA_PRESETS[config.preset ?? "default"] ?? SCHEMA_PRESETS.default;
  const token = SCHEMA_TOKENS[config.token ?? preset.token] ?? SCHEMA_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: SCHEMA_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  schemaRegistry.set(entryId, entry);
  notifySchemaListeners("register", entry);
  return entry;
}

function updateSchema(id, patch = {}) {
  const entry = schemaRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifySchemaListeners("update", entry);
  return entry;
}

function resolveSchema(id) {
  const entry = schemaRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listSchemaEntries(filter = {}) {
  let items = Array.from(schemaRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onSchemaEvent(listener) {
  SCHEMA_listeners.add(listener);
  return () => SCHEMA_listeners.delete(listener);
}

function notifySchemaListeners(type, entry) {
  for (const listener of SCHEMA_listeners) {
    try {
      listener({ type, entry, registrySize: schemaRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:forms:schema] listener error", err.message);
    }
  }
}

function getSchemaMetrics() {
  const items = listSchemaEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(SCHEMA_TOKENS).length,
    presets: Object.keys(SCHEMA_PRESETS).length,
  };
}

async function runMedxSchema() {
  console.log("[medx:ui:forms:schema] runtime initialized");
  console.log(`[medx:ui:forms:schema] tokens=${Object.keys(SCHEMA_TOKENS).length} presets=${Object.keys(SCHEMA_PRESETS).length}`);

  const events = [];
  onSchemaEvent((e) => events.push(e.type));

  const domains = Object.keys(SCHEMA_SUPPLY_CHAIN);
  const presets = Object.keys(SCHEMA_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerSchema({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "forms/schema" },
    });
  }

  const first = listSchemaEntries()[0];
  if (first) updateSchema(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getSchemaMetrics();
  const resolved = first ? resolveSchema(first.id) : null;

  console.log(`[medx:ui:forms:schema] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:forms:schema] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:forms:schema] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:forms:schema] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:forms:schema] bootstrap complete");
}

module.exports = runMedxSchema;
